noffi-shout.code:
// 'sh/shout' (an import) and 'shout' (local) would be called identically.
// Here we just call the local one — the point is there's no glue either way.
Def shout Fn {phrase: string}
  str-cat(upper(phrase) "!")
shout({phrase: "no ffi"})

typed-byte-add-ok.code:
// A typed parameter is checked at the call boundary.
Def byte-add Fn {a: u8 b: u8}
  add(a b)
byte-add({a: 100 b: 50})

typed-byte-add-bad.code:
// The same function rejects an out-of-range value.
Def byte-add Fn {a: u8 b: u8}
  add(a b)
byte-add({a: 300 b: 1})

syntax-chain.code:
// '.name(...)' makes the receiver the call's first argument.
// This reads as str-cat(upper("hello") ", world!").
"hello".upper().str-cat(", world!")

eval-fn-by-name.code:
Def delete-file Fn {path force}
  [path force]
// by name…
delete-file({path: "foo.md" force: true})

eval-fn-by-order.code:
Def delete-file Fn {path force}
  [path force]
// …and by order
delete-file("foo.md" true)

sf-fn-shout.code:
Def shout Fn {phrase: string}
  str-cat(upper(phrase) "!")
shout("hi")

sf-let.code:
Let {radius: 10
     area: mul(pi mul(radius radius))}
  str-cat("area = " to-string(area))

sf-defmacro.code:
DefMacro unless {cond body}
  Quasi If Unquote(cond) {} Unquote(body)
Let {x: 10}
  Unless gt(x 100) "x is not huge"

pm-describe.code:
Def describe Fn {r}
  Match r [
    (ok(v)   str-cat("got " to-string(v)))
    (err(e)  str-cat("failed: " e))
  ]
describe(ok(42))

macro-swap.code:
DefMacro swap {a b}
  Quasi [Unquote(b) Unquote(a)]
Let {x: 1 y: 2}
  Swap x y

macro-and.code:
DefMacro and {a b}
  Quasi If Unquote(a) Unquote(b) false
Let {x: 5}
  And lt(x 10) gt(x 0)

macro-expand.code:
DefMacro and {a b}
  Quasi If Unquote(a) Unquote(b) false
expand(Quote And(p q))

macro-gensym.code:
Def fresh-pair Fn {}
  eq(gensym() gensym())
fresh-pair()

macro-trylet.code:
DefMacro try-let {binding body}
  Let {name: rec-key(binding) expr: rec-val(binding)}
    Quasi Match Unquote(expr) [
      (ok(Unquote(name))  Unquote(body))
      (err(e)             err(e))
    ]
Def parse Fn {x}
  Try-let {n: ok(x)}
  ok(add(n 1))
parse(41)
